const body = $input.first().json.body || $input.first().json;
const now = new Date();
const ticketId = body.ticket_id || ('HUM-' + Date.now().toString().slice(-6));
const hour = now.getHours();
const isWorkingHours = hour >= 9 && hour < 19;
const waitTime = isWorkingHours ? '2-3 hours' : 'next business day (9AM IST)';
const leadScore = body.lead_score || 0;
const isPriorityLead = leadScore >= 80 || (body.pcm_percentage || 0) >= 85 || body.interest_level === 'High';
return [{
  json: {
    ticket_id: ticketId,
    student_name: body.student_name || 'Unknown Student',
    student_email: body.student_email || '',
    city: body.city || 'Unknown',
    target_exam: body.target_exam || 'JEE/CET',
    student_message: body.message || '',
    reason_for_human: body.reason || 'Student requested human support',
    lead_score: leadScore,
    pcm_percentage: body.pcm_percentage || 0,
    interest_level: body.interest_level || 'Unknown',
    source: body.source || 'Chatbot',
    stage: body.stage || 'Lead',
    is_priority_lead: isPriorityLead,
    is_working_hours: isWorkingHours,
    wait_time: waitTime,
    raised_at: now.toISOString(),
    raised_at_readable: now.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
    assigned_to: isPriorityLead ? 'Senior Support (Senior Support)' : 'Support Team'
  }
}];

// Notify Lead Scoring Team's Lead Scoring module about this warm lead
// In production: POST to Lead Scoring Team's lead scoring webhook
const data = $input.first().json;
console.log('[GrowthDesk] Notifying lead scoring module:', data.student_name, 'Score:', data.lead_score);
return [{
  json: {
    forwarded_to: 'Lead Scoring Module (Lead Scoring Team)',
    student_name: data.student_name,
    lead_score: data.lead_score,
    action: 'Human contact requested — re-score after call',
    webhook_to_call: 'POST https://your-n8n-domain/webhook/growthdesk-lead-score',
    payload: {
      student_name: data.student_name,
      city: data.city,
      target_exam: data.target_exam,
      trigger: 'human_request',
      current_score: data.lead_score
    }
  }
}];

// Replace with Postgres node
// Query: SELECT * FROM tickets WHERE query_type='Human Request'
// AND status='Open' AND raised_at < NOW() - INTERVAL '3 hours'
const now = new Date();
return [{
  json: {
    check_time: now.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
    db_query: "SELECT ticket_id, student_name, student_email, city, lead_score FROM tickets WHERE query_type='Human Request' AND status='Open' AND raised_at < NOW() - INTERVAL '3 hours' ORDER BY lead_score DESC",
    note: 'Replace with Postgres node. Returns unresponded human requests sorted by lead score.'
  }
}];
